const now = new Date().toISOString();
const config = $('Configuration').first().json;

function cleanText(value) {
  return String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim();
}

function stableId(prefix, value) {
  // Non-cryptographic deterministic hash. Avoids requiring Node built-ins in self-hosted Code nodes.
  let hash = 0x811c9dc5;
  const input = String(value ?? '');
  for (let i = 0; i < input.length; i++) {
    hash ^= input.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193) >>> 0;
  }
  return `${prefix}_${hash.toString(16).padStart(8, '0')}`;
}

return items.map((item, index) => {
  const message = item.json;
  const messageId = message.id || message.messageId || message.threadId || `unknown_${index}`;
  const sourceUri = messageId === `unknown_${index}` ? '' : `gmail://message/${messageId}`;
  const subject = cleanText(message.subject);
  const from = cleanText(message.from || message.sender || '');
  const snippet = cleanText(message.snippet || message.textPlain || message.textHtml || '');
  const rawText = [subject, from, snippet].filter(Boolean).join(' | ');

  return {
    json: {
      order_import_id: stableId('order_import', messageId),
      order_id: message.threadId || messageId,
      source_type: 'email_receipt',
      source_system: 'gmail',
      source_uri: sourceUri,
      merchant_raw: from,
      merchant_normalized: '',
      ordered_at_raw: message.date || message.internalDate || '',
      ordered_at: '',
      delivered_at: '',
      item_text_raw: rawText || subject || 'UNPARSED_EMAIL',
      quantity_raw: '',
      unit_raw: '',
      price_amount: '',
      currency: 'CAD',
      category_hint_raw: '',
      extractor: config.extractor,
      extracted_at: now,
      parse_confidence: 0.25,
      ambiguity_notes: 'Candidate email import. Needs parsing/review before promotion.',
      dedupe_key: stableId('gmail_order', `${messageId}|${subject}`),
      review_state: 'new'
    }
  };
});

